patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 03bc0f16c893..8a12e86bd831 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -4528,6 +4528,22 @@ static Instruction *foldICmpXorXX(ICmpInst &I, const SimplifyQuery &Q,
       isKnownNonZero(A, Q.DL, /*Depth=*/0, Q.AC, Q.CxtI, Q.DT))
     return new ICmpInst(PredOut, Op0, Op1);

+  // (X ^ Y) == X  --> Y == 0
+  // (X ^ Y) != X  --> Y != 0
+  if (ICmpInst::isEquality(Pred)) {
+    Constant *Zero = ConstantInt::getNullValue(A->getType());
+    return new ICmpInst(Pred, A, Zero);
+  }
+
+  // If X is ~A2 (i.e., xor A2, -1), then (~A2 ^ Y) pred ~A2  --> (A2 ^ Y) swapped_pred A2
+  Value *A2;
+  if (ICmpInst::isSigned(Pred) && match(Op1, m_c_Xor(m_Value(A2), m_AllOnes()))) {
+    // Compute A2 ^ Y = ~(Op0) because Op0 = ~A2 ^ Y, so ~Op0 = A2 ^ Y
+    Value *NewXor = IC.Builder.CreateXor(Op0, Constant::getAllOnesValue(Op0->getType()));
+    ICmpInst::Predicate NewPred = ICmpInst::getSwappedPredicate(Pred);
+    return new ICmpInst(NewPred, NewXor, A2);
+  }
+
   return nullptr;
 }

log.source_program:
define i1 @test_sle_xor(i32 %x, i32 %y) {
  %xor1 = xor i32 %y, -1
  %xor2 = xor i32 %xor1, %x
  %r = icmp sle i32 %xor2, %xor1
  ret i1 %r
}

log.expect_optimized_program:
define i1 @test_sle_xor(i32 %x, i32 %y) {
  %1 = xor i32 %y, %x
  %r = icmp sge i32 %1, %y
  ret i1 %r
}

